// Normaliza para que siempre exista $json.document_text
// y añade metadatos básicos (file_name, mime_type, received_at)

return items.map((item) => {
  const j = item.json || {};
  const bin = item.binary?.data || {};

  let text = "";

  // Tu nodo "Extraer texto del archivo" devuelve j.text
  if (typeof j.text === "string") text = j.text;
  else if (typeof j.data === "string") text = j.data;
  else if (Array.isArray(j.data)) text = j.data.join("\n");
  else if (typeof j.content === "string") text = j.content;
  else if (typeof j.body === "string") text = j.body;

  text = (text || "")
    .replace(/\r/g, "")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();

  item.json = {
    ...j,
    document_text: text,
    file_name: bin.fileName ?? j.file_name ?? null,
    mime_type: bin.mimeType ?? j.mime_type ?? null,
    received_at: j.received_at ?? new Date().toISOString(),
  };

  return item;
});

// Salida estructurada final (para Webhook Response: "Last Node")
// Modo: Run once for all items

return items.map((item) => {
  const data = item.json || {};
  const o = data.output || {}; // <- contenido real extraído por la IA

  const now = new Date().toISOString();
  const project_id = `PLIEGO-${now.replace(/[-:TZ.]/g, "").slice(0, 14)}`;

  const ubic = o.ubicacion || {};
  const clas = o.clasificacion || {};
  const fechas = o.fechas || {};
  const pres = o.presupuesto || {};

  const ubicTxt = `${ubic.ciudad ?? ""} ${ubic.provincia ?? ""} ${ubic.pais ?? ""}`
    .replace(/\s+/g, " ")
    .trim();

  const resumen = [
    `Cliente: ${o.cliente ?? "N/D"}`,
    `Ubicación: ${ubicTxt || "N/D"}`,
    `Tipo: ${o.tipo_proyecto ?? "N/D"}`,
    `Línea negocio: ${clas.linea_negocio ?? "N/D"}`,
    `Complejidad: ${clas.complejidad ?? "N/D"} | Prioridad: ${clas.prioridad ?? "N/D"}`,
    `Entrega oferta: ${fechas.fecha_entrega_oferta ?? "N/D"}`,
    `Presupuesto: ${(pres.importe ?? "N/D")} ${(pres.moneda ?? "")}`.trim(),
  ].join("\n");

  return {
    json: {
      project_id,
      processed_at: now,
      source: {
        file_name: data.file_name ?? null,
        mime_type: data.mime_type ?? null,
        received_at: data.received_at ?? null,
      },
      ...data, // incluye output intacto
      resumen_para_email: resumen,
    },
  };
});
